const sysOut = $('Collect system metrics').first().json.stdout || '';
const dkrOut = $('Collect Docker container metrics').first().json.stdout || '';

const m = {};
for (const line of sysOut.split('\n')) {
  const idx = line.indexOf('=');
  if (idx > 0 && !line.startsWith('---') && !line.includes('|')) {
    m[line.substring(0, idx).trim()] = line.substring(idx + 1).trim();
  }
}

// CPU % from /proc/stat delta
let cpuPercent = 0;
if (m.CPU_DELTA) {
  const parts = m.CPU_DELTA.split(' ');
  if (parts.length >= 4) {
    const total1 = parseFloat(parts[0]) || 0;
    const idle1 = parseFloat(parts[1]) || 0;
    const total2 = parseFloat(parts[2]) || 0;
    const idle2 = parseFloat(parts[3]) || 0;
    const totalDiff = total2 - total1;
    const idleDiff = idle2 - idle1;
    cpuPercent = totalDiff > 0 ? Math.round(((totalDiff - idleDiff) / totalDiff) * 1000) / 10 : 0;
  }
}

const loadParts = (m.LOAD || '0 0 0').split(' ');
const memTotal = parseInt(m.MEM_TOTAL) || 0;
const memUsed = parseInt(m.MEM_USED) || 0;
const memPct = memTotal > 0 ? Math.round((memUsed / memTotal) * 100) : 0;
const diskPct = parseInt(m.DISK_PCT) || 0;
const inodePct = parseInt(m.INODE_PCT) || 0;
const swapTotal = parseInt(m.SWAP_TOTAL) || 0;
const swapUsed = parseInt(m.SWAP_USED) || 0;
const swapPct = swapTotal > 0 ? Math.round((swapUsed / swapTotal) * 100) : 0;
const cores = parseInt(m.CORES) || 1;
const zombieCount = parseInt(m.ZOMBIES) || 0;
const failedServices = parseInt(m.FAILED_SERVICES) || 0;
const connections = parseInt(m.CONNECTIONS) || 0;
let cpuTemp = 'N/A';
if (m.TEMP && m.TEMP !== 'N/A') cpuTemp = (parseInt(m.TEMP) / 1000).toFixed(1);

let uptimeDays = 0;
if (m.UPTIME) {
  const sd = new Date(m.UPTIME);
  if (!isNaN(sd)) uptimeDays = Math.floor((Date.now() - sd.getTime()) / 86400000);
}

// Parse filesystems
const filesystems = [];
const fsSectionMatch = sysOut.split('---FS---');
if (fsSectionMatch.length > 1) {
  const fsBlock = fsSectionMatch[1].split('---NET---')[0] || fsSectionMatch[1].split('---TOP5CPU---')[0] || fsSectionMatch[1];
  for (const line of fsBlock.split('\n')) {
    const cols = line.trim().split(/\s+/);
    if (cols.length >= 5 && cols[4].match(/\d+/)) {
      filesystems.push({
        device: cols[0],
        size: cols[1],
        used: cols[2],
        mountpoint: cols[5] || '/',
        percent: parseInt(cols[4].replace('%', '')) || 0
      });
    }
  }
}

// Parse network I/O
let netRxBytes = 0, netTxBytes = 0, netRxErrors = 0, netTxErrors = 0;
const netSection = sysOut.split('---NET---');
if (netSection.length > 1) {
  const netBlock = netSection[1].split('---TOP5CPU---')[0] || netSection[1];
  for (const line of netBlock.split('\n')) {
    if (!line.includes('|')) continue;
    const parts = line.split('|');
    if (parts.length >= 5) {
      netRxBytes += parseInt(parts[1]) || 0;
      netTxBytes += parseInt(parts[2]) || 0;
      netRxErrors += parseInt(parts[3]) || 0;
      netTxErrors += parseInt(parts[4]) || 0;
    }
  }
}

// Parse top 5 processes by CPU
const topProcessesCpu = [];
const topSection = sysOut.split('---TOP5CPU---');
if (topSection.length > 1) {
  const topBlock = topSection[1].split('ZOMBIES=')[0] || topSection[1];
  for (const line of topBlock.split('\n')) {
    if (!line.includes('|')) continue;
    const parts = line.split('|');
    if (parts.length >= 3) {
      topProcessesCpu.push({
        command: (parts[0] || '').trim(),
        cpu: parseFloat(parts[1]) || 0,
        mem: parseFloat(parts[2]) || 0,
        user: (parts[3] || '').trim()
      });
    }
  }
}

// Docker parsing
const sections = dkrOut.split('---STATS---');
const containerLines = (sections[0] || '').split('\n');
const statsAndHealth = (sections[1] || '').split('---HEALTH---');
const statsLines = (statsAndHealth[0] || '').split('\n');
const healthAndDisk = (statsAndHealth[1] || '').split('---DISKUSAGE---');
const healthLines = (healthAndDisk[0] || '').split('\n');
const diskUsageLines = (healthAndDisk[1] || '').split('\n');

let running = 0, total = 0;
const containers = [];
const statsMap = {};
const healthMap = {};

for (const line of containerLines) {
  if (line.startsWith('RUNNING=')) running = parseInt(line.split('=')[1]) || 0;
  else if (line.startsWith('TOTAL=')) total = parseInt(line.split('=')[1]) || 0;
  else if (line.includes('|')) {
    const [name, status, image] = line.split('|');
    if (name) containers.push({ name: name.trim(), status: (status || '').trim(), image: (image || '').trim() });
  }
}

for (const line of statsLines) {
  if (!line.includes('|')) continue;
  const [name, cpu, mem, memP, pids] = line.split('|');
  if (name) statsMap[name.trim()] = { cpu: (cpu || '').trim(), mem: (mem || '').trim(), memPct: (memP || '').trim(), pids: (pids || '').trim() };
}

for (const line of healthLines) {
  if (!line.includes('|')) continue;
  const parts = line.split('|');
  let name = (parts[0] || '').trim();
  if (name.startsWith('/')) name = name.substring(1);
  if (name) healthMap[name] = { restarts: parseInt(parts[1]) || 0, health: (parts[2] || 'none').trim() };
}

// Docker disk usage
const dockerDisk = { images_size: 'N/A', images_reclaimable: 'N/A', containers_size: 'N/A', volumes_size: 'N/A', build_cache_size: 'N/A', dangling_images: 0, unused_volumes: 0 };
for (const line of diskUsageLines) {
  if (line.startsWith('DANGLING=')) { dockerDisk.dangling_images = parseInt(line.split('=')[1]) || 0; continue; }
  if (line.startsWith('UNUSED_VOLS=')) { dockerDisk.unused_volumes = parseInt(line.split('=')[1]) || 0; continue; }
  if (!line.includes('|')) continue;
  const parts = line.split('|');
  const type = (parts[0] || '').trim();
  if (type === 'Images') { dockerDisk.images_size = (parts[2] || '').trim(); dockerDisk.images_reclaimable = (parts[3] || '').trim(); }
  else if (type === 'Containers') dockerDisk.containers_size = (parts[2] || '').trim();
  else if (type === 'Local Volumes') dockerDisk.volumes_size = (parts[2] || '').trim();
  else if (type === 'Build Cache') dockerDisk.build_cache_size = (parts[2] || '').trim();
}

const containerSummary = containers.map(c => {
  const s = statsMap[c.name] || {};
  const h = healthMap[c.name] || {};
  return { name: c.name, status: c.status, image: c.image, cpu: s.cpu || '0%', memory: s.mem || 'N/A', memoryPct: s.memPct || '0%', restarts: h.restarts || 0, healthCheck: h.health || 'none' };
});

const downCount = containers.filter(c => !c.status.startsWith('Up')).length;
const totalRestarts = containerSummary.reduce((sum, c) => sum + c.restarts, 0);

// Health score with expanded factors
let score = 100;
if (diskPct > 90) score -= 30; else if (diskPct > 80) score -= 15;
if (memPct > 95) score -= 25; else if (memPct > 85) score -= 10;
if (cpuPercent > 80) score -= 20; else if (cpuPercent > 50) score -= 10;
if (parseFloat(loadParts[0]) > cores * 1.5) score -= 10; else if (parseFloat(loadParts[0]) > cores) score -= 5;
if (inodePct > 90) score -= 20; else if (inodePct > 80) score -= 10;
if (swapPct > 80) score -= 10; else if (swapPct > 50) score -= 5;
if (totalRestarts > 5) score -= 15; else if (totalRestarts > 0) score -= 5;
if (downCount > 0) score -= (downCount * 10);
if (zombieCount > 0) score -= 5;
if (failedServices > 0) score -= 10;
const reclaimStr = dockerDisk.images_reclaimable || '';
if (reclaimStr.includes('%)')) {
  const reclaimPct = parseInt(reclaimStr.match(/(\d+)%/)?.[1] || '0');
  if (reclaimPct > 50) score -= 5;
}
score = Math.max(0, score);

return [{ json: {
  timestamp: new Date().toISOString(),
  hostname: m.HOST || 'unknown',
  uptime_days: uptimeDays,
  cpu_percent: cpuPercent,
  cpu_load_1m: parseFloat(loadParts[0]) || 0,
  cpu_load_5m: parseFloat(loadParts[1]) || 0,
  cpu_load_15m: parseFloat(loadParts[2]) || 0,
  cores: cores,
  memory_total_mb: memTotal,
  memory_used_mb: memUsed,
  memory_percent: memPct,
  disk_total: m.DISK_TOTAL || 'N/A',
  disk_used: m.DISK_USED || 'N/A',
  disk_percent: diskPct,
  inode_percent: inodePct,
  swap_total_mb: swapTotal,
  swap_used_mb: swapUsed,
  swap_percent: swapPct,
  cpu_temp_c: cpuTemp,
  filesystems: filesystems,
  net_rx_bytes: netRxBytes,
  net_tx_bytes: netTxBytes,
  net_rx_errors: netRxErrors,
  net_tx_errors: netTxErrors,
  top_processes_cpu: topProcessesCpu,
  zombie_count: zombieCount,
  failed_services: failedServices,
  connections_established: connections,
  containers_running: running,
  containers_total: total,
  containers_down: downCount,
  total_restarts: totalRestarts,
  health_score: score,
  containers: containerSummary,
  docker_disk: dockerDisk
}}];

const metrics = $('Parse and normalize all metrics').first().json;
const config = $('⚙️ Configure monitoring settings').first().json;

const historyItems = $('Read metrics history (last 7 days)').all();
let historyText = 'No historical data available yet (first run).';
if (historyItems.length > 0 && historyItems[0].json.date) {
  const recent = historyItems.slice(-7);
  historyText = 'HISTORICAL DATA (last ' + recent.length + ' days):\n';
  for (const item of recent) {
    const h = item.json;
    historyText += h.date + ': CPU=' + (h.cpu_percent || h.cpu_load || 'N/A') + '% Mem=' + (h.memory_percent || 'N/A') + '% Disk=' + (h.disk_percent || 'N/A') + '% Swap=' + (h.swap_percent || 'N/A') + '% Score=' + (h.health_score || 'N/A') + ' Containers=' + (h.containers_running || '?') + '/' + (h.containers_total || '?') + ' Net_RX=' + (h.net_rx_bytes || 'N/A') + ' Net_TX=' + (h.net_tx_bytes || 'N/A') + '\n';
  }
}

let containerTable = '';
for (const c of (metrics.containers || [])) {
  const icon = c.status.startsWith('Up') ? 'UP' : 'DOWN';
  const restart = c.restarts > 0 ? ' (' + c.restarts + ' restarts)' : '';
  containerTable += icon + ' ' + c.name + ': ' + c.cpu + ' CPU, ' + c.memory + restart + '\n';
}

let fsTable = '';
for (const fs of (metrics.filesystems || [])) {
  fsTable += fs.mountpoint + ': ' + fs.used + '/' + fs.size + ' (' + fs.percent + '%) [' + fs.device + ']\n';
}

let topProcs = '';
for (const p of (metrics.top_processes_cpu || [])) {
  topProcs += p.command + ': ' + p.cpu + '% CPU, ' + p.mem + '% MEM (user: ' + p.user + ')\n';
}

const dk = metrics.docker_disk || {};

const prompt = 'Analyze this homelab and respond with ONLY valid JSON (no markdown, no code fences).\n\n' +
  'SYSTEM METRICS:\n' +
  '- Host: ' + metrics.hostname + ' | Uptime: ' + metrics.uptime_days + ' days | Cores: ' + metrics.cores + '\n' +
  '- CPU: ' + metrics.cpu_percent + '% utilization | Load: ' + metrics.cpu_load_1m + '/' + metrics.cpu_load_5m + '/' + metrics.cpu_load_15m + '\n' +
  '- Memory: ' + metrics.memory_used_mb + 'MB/' + metrics.memory_total_mb + 'MB (' + metrics.memory_percent + '%)\n' +
  '- Swap: ' + metrics.swap_used_mb + 'MB/' + metrics.swap_total_mb + 'MB (' + metrics.swap_percent + '%)\n' +
  '- Temp: ' + metrics.cpu_temp_c + 'C | Connections: ' + metrics.connections_established + ' | Zombies: ' + metrics.zombie_count + ' | Failed services: ' + metrics.failed_services + '\n\n' +
  'FILESYSTEMS:\n' + (fsTable || 'Root only: ' + metrics.disk_used + '/' + metrics.disk_total + ' (' + metrics.disk_percent + '%)\n') + '\n' +
  'NETWORK I/O (total across physical interfaces):\n' +
  '- RX: ' + (metrics.net_rx_bytes / 1073741824).toFixed(2) + ' GB | TX: ' + (metrics.net_tx_bytes / 1073741824).toFixed(2) + ' GB\n' +
  '- Errors: RX=' + metrics.net_rx_errors + ' TX=' + metrics.net_tx_errors + '\n\n' +
  'TOP 5 PROCESSES BY CPU:\n' + (topProcs || 'N/A\n') + '\n' +
  'DOCKER ECOSYSTEM:\n' +
  '- Containers: ' + metrics.containers_running + ' running / ' + metrics.containers_total + ' total (' + metrics.containers_down + ' down)\n' +
  '- Images: ' + dk.images_size + ' (reclaimable: ' + dk.images_reclaimable + ')\n' +
  '- Volumes: ' + dk.volumes_size + ' | Build cache: ' + dk.build_cache_size + '\n' +
  '- Dangling images: ' + dk.dangling_images + ' | Unused volumes: ' + dk.unused_volumes + '\n\n' +
  'CONTAINERS:\n' + containerTable + '\n' +
  historyText + '\n\n' +
  'Health Score: ' + metrics.health_score + '/100\n' +
  'Thresholds: Disk warn=' + (config.disk_warning_pct || 80) + '% crit=' + (config.disk_critical_pct || 90) + '% | Mem warn=' + (config.memory_warning_pct || 85) + '% crit=' + (config.memory_critical_pct || 95) + '%\n\n' +
  'Respond with this exact JSON structure:\n' +
  '{"status":"healthy|warning|critical","headline":"One-sentence summary","findings":[{"severity":"high|medium|low","title":"Short title","detail":"Explanation","command":"fix command or null"}],"trend_summary":"Historical comparison or null if no data","top_recommendation":"Single most impactful action"}';

return [{ json: { prompt: prompt } }];

const rawText = $json.text || $json.output || '{}';
const metrics = $('Parse and normalize all metrics').first().json;
const score = metrics.health_score || 0;
const startTime = new Date($('Parse and normalize all metrics').first().json.timestamp);

// Parse AI JSON response
let ai = {};
try {
  let cleaned = rawText.trim();
  if (cleaned.startsWith('```')) {
    cleaned = cleaned.replace(/^```(?:json)?\n?/, '').replace(/\n?```$/, '');
  }
  ai = JSON.parse(cleaned);
} catch (e) {
  ai = { status: 'warning', headline: 'AI response was not valid JSON', findings: [{ severity: 'medium', title: 'AI Parse Error', detail: rawText.substring(0, 300), command: null }], trend_summary: null, top_recommendation: 'Check AI model output format' };
}

// Token/cost tracking
let inputTokens = 0, outputTokens = 0;
if ($json.tokenUsageEstimate) {
  inputTokens = $json.tokenUsageEstimate.promptTokens || 0;
  outputTokens = $json.tokenUsageEstimate.completionTokens || 0;
}
if (inputTokens === 0) {
  const promptText = $('Build analysis prompt with history').first().json.prompt || '';
  inputTokens = Math.ceil((promptText.length + 800) / 4);
  outputTokens = Math.ceil(rawText.length / 4);
}
const costUsd = (inputTokens * 0.15 + outputTokens * 0.60) / 1000000;
const costDisplay = '$' + costUsd.toFixed(4);

// Colors
const green = 0x00cc66;
const yellow = 0xffaa00;
const red = 0xff3333;
const color = score >= 80 ? green : score >= 50 ? yellow : red;
const statusEmoji = score >= 80 ? '\u2705' : score >= 50 ? '\u26a0\ufe0f' : '\ud83d\udea8';

// Format bytes
const fmtBytes = (b) => {
  if (b >= 1073741824) return (b / 1073741824).toFixed(1) + ' GB';
  if (b >= 1048576) return (b / 1048576).toFixed(1) + ' MB';
  if (b >= 1024) return (b / 1024).toFixed(1) + ' KB';
  return b + ' B';
};

// Embed 1: Status header with inline fields
const fields = [
  { name: '\ud83d\udcca Health', value: score + '/100', inline: true },
  { name: '\ud83d\udda5\ufe0f CPU', value: metrics.cpu_percent + '%', inline: true },
  { name: '\ud83e\udde0 Memory', value: metrics.memory_percent + '%', inline: true },
  { name: '\ud83d\udcbe Disk /', value: metrics.disk_percent + '%', inline: true },
  { name: '\ud83d\udd04 Swap', value: metrics.swap_percent + '%', inline: true },
  { name: '\ud83d\udc33 Containers', value: metrics.containers_running + '/' + metrics.containers_total, inline: true }
];

// Add any filesystem over 75%
for (const fs of (metrics.filesystems || [])) {
  if (fs.percent >= 75 && fs.mountpoint !== '/') {
    fields.push({ name: '\ud83d\udcbe ' + fs.mountpoint, value: fs.percent + '%', inline: true });
  }
}

const embed1 = {
  title: ('\ud83c\udfe0 Homelab Health - ' + statusEmoji + ' ' + (ai.headline || 'Analysis complete')).substring(0, 256),
  color: color,
  fields: fields.slice(0, 9)
};

// Embed 2: Findings
let findingsText = '';
const findings = ai.findings || [];
if (findings.length === 0) {
  findingsText = '\u2705 All clear - no issues detected.';
} else {
  for (const f of findings.slice(0, 6)) {
    const icon = f.severity === 'high' ? '\ud83d\udd34' : f.severity === 'medium' ? '\ud83d\udfe1' : '\ud83d\udfe2';
    const tag = f.severity.toUpperCase();
    findingsText += icon + ' **' + tag + ': ' + (f.title || 'Issue') + '**\n';
    if (f.detail) findingsText += f.detail.substring(0, 200) + '\n';
    if (f.command) findingsText += '```\n' + f.command.substring(0, 120) + '\n```\n';
  }
}

const embed2 = {
  title: '\ud83d\udd0d Findings',
  description: findingsText.substring(0, 2000),
  color: color
};

// Embed 3: Docker ecosystem + trends
const dk = metrics.docker_disk || {};
let embed3Desc = '**Docker Disk**\n';
embed3Desc += '\ud83d\uddbc Images: ' + (dk.images_size || 'N/A') + ' (reclaimable: ' + (dk.images_reclaimable || 'N/A') + ')\n';
embed3Desc += '\ud83d\udce6 Volumes: ' + (dk.volumes_size || 'N/A') + ' | Cache: ' + (dk.build_cache_size || 'N/A') + '\n';
if (dk.dangling_images > 0 || dk.unused_volumes > 0) {
  embed3Desc += '\u26a0\ufe0f Dangling images: ' + dk.dangling_images + ' | Unused volumes: ' + dk.unused_volumes + '\n';
}
embed3Desc += '\n**Network I/O**\n';
embed3Desc += '\ud83d\udce5 RX: ' + fmtBytes(metrics.net_rx_bytes) + ' | \ud83d\udce4 TX: ' + fmtBytes(metrics.net_tx_bytes) + '\n';
if (metrics.net_rx_errors > 0 || metrics.net_tx_errors > 0) {
  embed3Desc += '\u26a0\ufe0f Errors: RX=' + metrics.net_rx_errors + ' TX=' + metrics.net_tx_errors + '\n';
}
if (ai.trend_summary) {
  embed3Desc += '\n**Trends**\n' + ai.trend_summary.substring(0, 300) + '\n';
}
if (ai.top_recommendation) {
  embed3Desc += '\n\ud83d\udca1 **Top Recommendation:** ' + ai.top_recommendation.substring(0, 200);
}

const embed3 = {
  title: '\ud83d\udc33 Docker & Trends',
  description: embed3Desc.substring(0, 1500),
  color: color
};

// Embed 4: Footer
const now = new Date();
const cstTime = now.toLocaleString('en-US', { timeZone: 'America/Chicago', hour: 'numeric', minute: '2-digit', hour12: true });
const durationMs = now.getTime() - startTime.getTime();
const durationSec = (durationMs / 1000).toFixed(1);

const embed4 = {
  description: metrics.hostname + ' | ' + cstTime + ' CST | ' + durationSec + 's | API: ' + costDisplay,
  color: color
};

const payload = {
  embeds: [embed1, embed2, embed3, embed4]
};

return { json: payload };

const config = $('⚙️ Alert settings').first().json;
const out = $json.stdout || '';
const lines = out.split('\n');
const m = {};
const downContainers = [];
const highRestarts = [];

for (const line of lines) {
  if (line.startsWith('DOWN=')) {
    downContainers.push(line.replace('DOWN=', '').trim());
  } else if (line.startsWith('RESTART=')) {
    const val = line.replace('RESTART=', '');
    const cleaned = val.startsWith('/') ? val.substring(1) : val;
    const parts = cleaned.split('|');
    const count = parseInt(parts[1]) || 0;
    if (count >= 3) highRestarts.push({ name: parts[0], count: count });
  } else {
    const idx = line.indexOf('=');
    if (idx > 0) m[line.substring(0, idx).trim()] = line.substring(idx + 1).trim();
  }
}

const diskPct = parseInt(m.DISK_PCT) || 0;
const memPct = parseInt(m.MEM_PCT) || 0;
const load = parseFloat(m.LOAD) || 0;
const cores = parseInt(m.CORES) || 1;
const inodePct = parseInt(m.INODE_PCT) || 0;

const DISK_CRIT = config.disk_critical_pct || 90;
const MEM_CRIT = config.memory_critical_pct || 95;
const INODE_CRIT = config.inode_critical_pct || 90;
const LOAD_MULT = config.load_multiplier || 1.5;

const alerts = [];
if (diskPct >= DISK_CRIT) alerts.push('🔴 **DISK CRITICAL:** ' + diskPct + '% used (threshold: ' + DISK_CRIT + '%)');
if (memPct >= MEM_CRIT) alerts.push('🔴 **MEMORY CRITICAL:** ' + memPct + '% used (threshold: ' + MEM_CRIT + '%)');
if (inodePct >= INODE_CRIT) alerts.push('🔴 **INODE CRITICAL:** ' + inodePct + '% used');
if (load > cores * LOAD_MULT) alerts.push('🟡 **HIGH CPU LOAD:** ' + load.toFixed(1) + ' (' + cores + ' cores, threshold: ' + (cores * LOAD_MULT).toFixed(1) + ')');
for (const c of downContainers) alerts.push('🔴 **CONTAINER DOWN:** ' + c);
for (const r of highRestarts) alerts.push('🟡 **RESTART LOOP:** ' + r.name + ' has restarted ' + r.count + ' times');

return { json: { has_critical: alerts.length > 0, alert_count: alerts.length, alerts: alerts, alert_message: alerts.join('\n\n'), disk_pct: diskPct, mem_pct: memPct, load: load, containers_down: downContainers.length } };

const data = $json;
const payload = {
  content: '🚨 **HOMELAB CRITICAL ALERT**',
  embeds: [{
    title: data.alert_count + ' Critical Issue(s) Detected',
    description: data.alert_message.substring(0, 4000),
    color: 0xff3333,
    fields: [
      { name: 'Disk', value: data.disk_pct + '%', inline: true },
      { name: 'Memory', value: data.mem_pct + '%', inline: true },
      { name: 'CPU Load', value: data.load.toFixed(1), inline: true }
    ],
    timestamp: new Date().toISOString()
  }]
};
return { json: payload };

const input = $json;
const spreadsheetId = input.spreadsheetId;
const spreadsheetUrl = input.spreadsheetUrl;

const sheets = input.sheets || [];
const metricsSheet = sheets.find(s => s.properties && s.properties.title === 'metrics');
const sheetId = metricsSheet ? metricsSheet.properties.sheetId : 0;

const headers = [
  'date', 'hostname', 'cpu_percent', 'cpu_load', 'memory_percent',
  'disk_percent', 'inode_percent', 'swap_percent', 'health_score',
  'containers_running', 'containers_total', 'net_rx_bytes', 'net_tx_bytes',
  'docker_reclaimable_gb', 'zombie_count', 'connections'
];

const headerCells = headers.map(h => ({
  userEnteredValue: { stringValue: h },
  userEnteredFormat: {
    backgroundColor: { red: 0.15, green: 0.15, blue: 0.18 },
    textFormat: {
      bold: true,
      fontSize: 10,
      foregroundColor: { red: 0.90, green: 0.90, blue: 0.93 }
    },
    horizontalAlignment: 'CENTER',
    borders: {
      bottom: { style: 'SOLID', width: 2, color: { red: 0.20, green: 0.60, blue: 0.86 } }
    }
  }
}));

const columnWidths = [100, 120, 90, 85, 115, 95, 95, 95, 100, 135, 120, 110, 110, 140, 100, 100];

const requests = [
  {
    updateCells: {
      rows: [{ values: headerCells }],
      start: { sheetId: sheetId, rowIndex: 0, columnIndex: 0 },
      fields: 'userEnteredValue,userEnteredFormat'
    }
  },
  {
    updateSheetProperties: {
      properties: { sheetId: sheetId, gridProperties: { frozenRowCount: 1 } },
      fields: 'gridProperties.frozenRowCount'
    }
  },
  {
    updateSheetProperties: {
      properties: { sheetId: sheetId, tabColorStyle: { rgbColor: { red: 0.20, green: 0.60, blue: 0.86 } } },
      fields: 'tabColorStyle'
    }
  },
  // Health score gradient (col 8)
  {
    addConditionalFormatRule: {
      rule: {
        ranges: [{ sheetId: sheetId, startRowIndex: 1, startColumnIndex: 8, endColumnIndex: 9 }],
        gradientRule: {
          minpoint: { color: { red: 0.92, green: 0.60, blue: 0.60 }, type: 'NUMBER', value: '0' },
          midpoint: { color: { red: 1.0, green: 0.85, blue: 0.40 }, type: 'NUMBER', value: '65' },
          maxpoint: { color: { red: 0.56, green: 0.87, blue: 0.56 }, type: 'NUMBER', value: '100' }
        }
      },
      index: 0
    }
  },
  // CPU % gradient (col 2)
  {
    addConditionalFormatRule: {
      rule: {
        ranges: [{ sheetId: sheetId, startRowIndex: 1, startColumnIndex: 2, endColumnIndex: 3 }],
        gradientRule: {
          minpoint: { color: { red: 0.56, green: 0.87, blue: 0.56 }, type: 'NUMBER', value: '0' },
          midpoint: { color: { red: 1.0, green: 0.85, blue: 0.40 }, type: 'NUMBER', value: '50' },
          maxpoint: { color: { red: 0.92, green: 0.60, blue: 0.60 }, type: 'NUMBER', value: '100' }
        }
      },
      index: 1
    }
  },
  // Memory % gradient (col 4)
  {
    addConditionalFormatRule: {
      rule: {
        ranges: [{ sheetId: sheetId, startRowIndex: 1, startColumnIndex: 4, endColumnIndex: 5 }],
        gradientRule: {
          minpoint: { color: { red: 0.56, green: 0.87, blue: 0.56 }, type: 'NUMBER', value: '0' },
          midpoint: { color: { red: 1.0, green: 0.85, blue: 0.40 }, type: 'NUMBER', value: '80' },
          maxpoint: { color: { red: 0.92, green: 0.60, blue: 0.60 }, type: 'NUMBER', value: '100' }
        }
      },
      index: 2
    }
  },
  // Disk % gradient (col 5)
  {
    addConditionalFormatRule: {
      rule: {
        ranges: [{ sheetId: sheetId, startRowIndex: 1, startColumnIndex: 5, endColumnIndex: 6 }],
        gradientRule: {
          minpoint: { color: { red: 0.56, green: 0.87, blue: 0.56 }, type: 'NUMBER', value: '0' },
          midpoint: { color: { red: 1.0, green: 0.85, blue: 0.40 }, type: 'NUMBER', value: '75' },
          maxpoint: { color: { red: 0.92, green: 0.60, blue: 0.60 }, type: 'NUMBER', value: '100' }
        }
      },
      index: 3
    }
  },
  // Inode % gradient (col 6)
  {
    addConditionalFormatRule: {
      rule: {
        ranges: [{ sheetId: sheetId, startRowIndex: 1, startColumnIndex: 6, endColumnIndex: 7 }],
        gradientRule: {
          minpoint: { color: { red: 0.56, green: 0.87, blue: 0.56 }, type: 'NUMBER', value: '0' },
          midpoint: { color: { red: 1.0, green: 0.85, blue: 0.40 }, type: 'NUMBER', value: '80' },
          maxpoint: { color: { red: 0.92, green: 0.60, blue: 0.60 }, type: 'NUMBER', value: '100' }
        }
      },
      index: 4
    }
  },
  // Swap % gradient (col 7)
  {
    addConditionalFormatRule: {
      rule: {
        ranges: [{ sheetId: sheetId, startRowIndex: 1, startColumnIndex: 7, endColumnIndex: 8 }],
        gradientRule: {
          minpoint: { color: { red: 0.56, green: 0.87, blue: 0.56 }, type: 'NUMBER', value: '0' },
          midpoint: { color: { red: 1.0, green: 0.85, blue: 0.40 }, type: 'NUMBER', value: '50' },
          maxpoint: { color: { red: 0.92, green: 0.60, blue: 0.60 }, type: 'NUMBER', value: '100' }
        }
      },
      index: 5
    }
  }
];

columnWidths.forEach((width, i) => {
  requests.push({
    updateDimensionProperties: {
      range: { sheetId: sheetId, dimension: 'COLUMNS', startIndex: i, endIndex: i + 1 },
      properties: { pixelSize: width },
      fields: 'pixelSize'
    }
  });
});

return {
  json: {
    spreadsheetId,
    spreadsheetUrl,
    batchUpdateBody: { requests },
    sheet_id: spreadsheetId,
    sheet_url: spreadsheetUrl
  }
};

const metrics = $('Parse and normalize all metrics').first().json;
const dk = metrics.docker_disk || {};

// Parse reclaimable to GB
let reclaimableGb = 0;
const reclaimStr = dk.images_reclaimable || '';
if (reclaimStr.includes('GB')) {
  reclaimableGb = parseFloat(reclaimStr) || 0;
} else if (reclaimStr.includes('MB')) {
  reclaimableGb = (parseFloat(reclaimStr) || 0) / 1024;
}

return [{
  json: {
    date: metrics.timestamp.substring(0, 10),
    hostname: metrics.hostname,
    cpu_percent: metrics.cpu_percent,
    cpu_load: metrics.cpu_load_1m,
    memory_percent: metrics.memory_percent,
    disk_percent: metrics.disk_percent,
    inode_percent: metrics.inode_percent,
    swap_percent: metrics.swap_percent,
    health_score: metrics.health_score,
    containers_running: metrics.containers_running,
    containers_total: metrics.containers_total,
    net_rx_bytes: metrics.net_rx_bytes,
    net_tx_bytes: metrics.net_tx_bytes,
    docker_reclaimable_gb: Math.round(reclaimableGb * 100) / 100,
    zombie_count: metrics.zombie_count,
    connections: metrics.connections_established
  }
}];
